import React from "react";
import { motion } from "framer-motion";
import "./index.css";

export default function App() {
  return (
    <div className="bg-gradient-to-br from-black via-gray-900 to-black text-white min-h-screen overflow-x-hidden">
      <Navbar />
      <Hero />
      <Experience />
      <Projects />
      <Contact />
    </div>
  );
}

function Navbar() {
  return (
    <div className="flex justify-between items-center px-10 py-5 backdrop-blur-xl bg-white/5 sticky top-0 z-50 border-b border-white/10">
      <h1 className="text-xl font-bold tracking-widest">KASHIF</h1>
      <div className="space-x-6 text-sm">
        <a href="#exp" className="hover:text-blue-400 transition">Experience</a>
        <a href="#projects" className="hover:text-blue-400 transition">Projects</a>
        <a href="#contact" className="hover:text-blue-400 transition">Contact</a>
      </div>
    </div>
  );
}

function Hero() {
  return (
    <div className="text-center py-40 px-6">

      <motion.h1
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        className="text-6xl md:text-7xl font-bold tracking-wide"
      >
        Muhammad Kashif
      </motion.h1>

      <motion.p
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.5 }}
        className="mt-6 text-gray-400 text-xl"
      >
        Full Stack Engineer | Real-Time Systems Specialist
      </motion.p>

      <motion.div
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.8 }}
        className="mt-10 bg-white/5 p-8 rounded-2xl backdrop-blur-xl border border-white/10 max-w-2xl mx-auto shadow-xl"
      >
        <p className="text-gray-300 leading-relaxed">
          Results-driven Software Engineer with 3+ years of experience building scalable,
          high-performance real-time applications using React, Node.js, and WebSockets.
        </p>
      </motion.div>

      {/* <div className="mt-10 flex justify-center gap-4">
        <button className="px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 transition">
          View Projects
        </button>
        <button className="px-6 py-2 border border-white/20 rounded-lg hover:bg-white/10 transition">
          Contact Me
        </button>
      </div> */}

      <a href="#projects">
        <button className="px-6 py-2 bg-blue-600 rounded-lg hover:bg-blue-500 transition">
          View Projects
        </button>
      </a>

      <a href="#contact">
        <button className="px-6 py-2 border border-white/20 rounded-lg hover:bg-white/10 transition">
          Contact Me
        </button>
      </a>

    </div>
  );
}

function Experience() {
  return (
    <div id="exp" className="px-10 py-24">
      <h2 className="text-4xl font-bold mb-12 text-center">Experience</h2>

      <div className="max-w-4xl mx-auto bg-white/5 p-10 rounded-2xl backdrop-blur-xl border border-white/10 hover:scale-[1.02] transition shadow-lg">
        <ul className="space-y-4 text-gray-300 text-lg">
          <li>✔ Led integration of sensor systems with real-time pipelines</li>
          <li>✔ Built live air traffic monitoring using React Leaflet</li>
          <li>✔ Used WebSockets, TCP, UDP for low-latency systems</li>
          <li>✔ Developed high-availability 24/7 applications</li>
        </ul>
      </div>
    </div>
  );
}

function Projects() {
  return (
    <div id="projects" className="px-10 py-24">
      <h2 className="text-4xl font-bold mb-12 text-center">Projects</h2>

      <div className="grid md:grid-cols-3 gap-8 max-w-6xl mx-auto">
        <Card
          title="Air Traffic Application"
          desc={
            <>
              Developed a high-availability <strong>React-Leaflet</strong> application for live air traffic monitoring and real-time visualization.
              Implemented dynamic map markers, layers, and popups to show aircraft positions, maintenance alerts, and operational data.
              Ensured 24/7 uptime with minimal downtime and optimized performance under continuous usage.
            </>
          }
        />

        <Card
          title="Map Drawing Tools"
          desc={
            <>
              Designed interactive map drawing tools for creating <strong>polygons, lines, and markers</strong> directly on the map.
              Captured coordinates in real-time with database integration, allowing users to save, edit, and reload custom shapes.
              Features include dynamic layers, tooltips, and markers for an intuitive and smooth user experience.
            </>
          }
        />

        <Card
          title="Sensor Integration"
          desc={
            <>
              Led integration of various <strong>sensors</strong> into the system, collaborating with third-party vendors and ensuring seamless data flow.
              Managed Web application to display sensor locations and live air traffic data in real-time.
              Utilized TCP, UDP, and WebSocket protocols for low-latency communication and ensured system stability with 24/7 high-availability applications.
            </>
          }
        />
      </div>
    </div>
  );
}

function Card({ title, desc }) {
  return (
    <div className="bg-white/5 p-8 rounded-2xl backdrop-blur-xl border border-white/10 hover:scale-105 hover:border-blue-500 transition shadow-lg">
      <h3 className="text-2xl font-semibold">{title}</h3>
      <p className="mt-3 text-gray-400">{desc}</p>
    </div>
  );
}

// function Card({ title, desc }) {
//   return (
//     <div className="bg-white/5 p-8 rounded-2xl backdrop-blur-xl border border-white/10 hover:scale-105 hover:border-blue-500 transition shadow-lg">
//       <h3 className="text-2xl font-semibold">{title}</h3>
//       <p className="mt-3 text-gray-400">{desc}</p>
//     </div>
//   );
// }

function Contact() {
  return (
    <div id="contact" className="px-10 py-24">
      <h2 className="text-4xl font-bold mb-12 text-center">Contact</h2>

      <form className="space-y-5 max-w-xl mx-auto bg-white/5 p-10 rounded-2xl backdrop-blur-xl border border-white/10 shadow-lg">
        <input placeholder="Name" className="w-full p-3 rounded bg-black/40 outline-none" />
        <input placeholder="Email" className="w-full p-3 rounded bg-black/40 outline-none" />
        <textarea placeholder="Message" className="w-full p-3 rounded bg-black/40 outline-none" />

        <button className="w-full bg-blue-600 py-3 rounded-lg hover:bg-blue-500 transition">
          Send Message
        </button>
      </form>
    </div>
  );
}
